mapper.select:
SELECT * FROM im_ticket
WHERE deleted = 0

    AND channel = #{channel}


    AND capital_id = #{capitalId}


    AND status = #{status}


    AND assigned_agent_id = #{agentId}


    AND (ticket_no LIKE CONCAT('%', #{keyword}, '%')
    OR description LIKE CONCAT('%', #{keyword}, '%')
    OR user_name LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY created_at DESC
